example.code:
{
  "experiment_id": "checkout-v2-button-color",
  "hypothesis": "Changing the checkout button to high-contrast blue increases successful checkout conversion by lowering visual scanning effort.",
  "primary_metric": {
    "name": "checkout_conversion_rate",
    "delta_direction": "increase"
  },
  "secondary_metrics": [
    "time_to_checkout",
    "cart_abandonment"
  ],
  "guardrails": [
    {
      "name": "p95_latency_ms",
      "floor": "<=250"
    },
    {
      "name": "error_rate",
      "floor": "<=0.005"
    },
    {
      "name": "revenue_per_user",
      "floor": ">=baseline"
    }
  ],
  "mde": {
    "effect_size": "+2pp",
    "sample_size": 24000,
    "runtime_days": 14
  },
  "srm_passed": true,
  "decision": "ship"
}
